import './formulario-de-preguntas.css';

function FormularioDePreguntasEstudiante() {
  return (
    <div className="contenedorPadrePregunta">
      <div className="texto-de-pregunta">
        {/* Aquí irá la variable {pregunta.texto} más adelante */}
        Lorem ipsum dolor sit amet consectetur adipisicing elit...
      </div>
      
      <div className="respuestas">
        <button>A: <span>Respuesta A</span></button>
        <button>B: <span>Respuesta B</span></button>
        <button>C: <span>Respuesta C</span></button>
        <button>D: <span>Respuesta D</span></button>
      </div>
    </div>
  );
}

export default FormularioDePreguntasEstudiante;
